module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const range = Math.abs(parseFloat(args.range)) || 5;
const grid = String(args.grid) !== 'false';
const color = args.color || 'var(--accent-color)';
const sizes = { sm: '260px', md: '360px', lg: '460px' };
const width = sizes[String(args.size || 'md').toLowerCase()] || '360px';
const xlabel = String(args.xlabel || '').trim();
const ylabel = String(args.ylabel || '').trim();
const S = 100, C = 50, K = 44 / range; // map units→% (44% each side)
const px = (x) => (C + x * K).toFixed(2);
const py = (y) => (C - y * K).toFixed(2);
let g = '';
if (grid) {
  for (let i = -range; i <= range; i++) {
    if (i === 0) continue;
    g += `<line x1="${px(i)}" y1="0" x2="${px(i)}" y2="${S}" class="mdp-cp-grid"/>`;
    g += `<line x1="0" y1="${py(i)}" x2="${S}" y2="${py(i)}" class="mdp-cp-grid"/>`;
  }
}
const axes = `<line x1="0" y1="${C}" x2="${S}" y2="${C}" class="mdp-cp-axis"/><line x1="${C}" y1="0" x2="${C}" y2="${S}" class="mdp-cp-axis"/>`;
let alabels = '';
if (xlabel) alabels += `<text x="${px(range)}" y="${C}" dx="-2" dy="4" class="mdp-cp-lbl" text-anchor="end">${esc(xlabel)}</text>`;
if (ylabel) alabels += `<text x="${C}" y="${py(range)}" dx="3" dy="4" class="mdp-cp-lbl">${esc(ylabel)}</text>`;
let items = '';
sections.map((s) => (s || '').trim()).filter(Boolean).forEach((s) => {
  const vm = s.match(/^->\s*(-?[\d.]+)\s*,\s*(-?[\d.]+)\s*([\s\S]*)$/);
  const pm = s.match(/^(-?[\d.]+)\s*,\s*(-?[\d.]+)\s*([\s\S]*)$/);
  if (vm) {
    const x = parseFloat(vm[1]), y = parseFloat(vm[2]);
    items += `<line x1="${px(0)}" y1="${py(0)}" x2="${px(x)}" y2="${py(y)}" class="mdp-cp-vec" marker-end="url(#mdp-cp-arrow)"/>`;
    if (vm[3].trim()) items += `<text x="${px(x)}" y="${py(y)}" dx="4" dy="-4" class="mdp-cp-lbl">${esc(vm[3].trim())}</text>`;
  } else if (pm) {
    const x = parseFloat(pm[1]), y = parseFloat(pm[2]);
    items += `<circle cx="${px(x)}" cy="${py(y)}" r="1.6" class="mdp-cp-pt"/>`;
    if (pm[3].trim()) items += `<text x="${px(x)}" y="${py(y)}" dx="3" dy="-3" class="mdp-cp-lbl">${esc(pm[3].trim())}</text>`;
  }
});
return `\n\n<div class="mdp-mod-coordplane" style="--cp-color:${color}; width: min(100%, ${width});"><svg viewBox="0 0 100 100" preserveAspectRatio="xMidYMid meet">` +
  `<defs><marker id="mdp-cp-arrow" markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto"><path d="M0,0 L6,3 L0,6 z" fill="${color}"/></marker></defs>` +
  `${g}${axes}${alabels}${items}</svg></div>\n\n`;
